    )
    // ...
}



Also add the following function:


export async function removeShippingMethodFromCart(shippingMethodId: string) {
  const headers = {
    ...(await getAuthHeaders()),
  }

  const next = {
    ...(await getCacheOptions("fulfillment")),
  }

  return sdk.client
    .fetch<Record<string, unknown>>(
      `/store/shipping-methods/${shippingMethodId}`,
      {
        method: "DELETE",
        headers,
        next,
      }
    )
    .then(async () => {
      const cartCacheTag = await getCacheTag("carts")
      revalidateTag(cartCacheTag)
    })
    .catch(() => null)
}



These changes enable three core behaviors:


 * The storefront can attach ApiShip-specific selection data when applying a
   shipping method.
 * It can read the saved data back from the cart when the page is reloaded.
 * It can fully clear the selection by removing the shipping method from the
   cart when the customer decides to reset their choice.



3. APISHIP DATA FETCHING


To properly render ApiShip delivery options in the shipping step, the storefront
needs access to dynamic calculation data, pickup point details, and the list of
available providers. In addition to tariffs and pickup points, the storefront
also retrieves provider metadata to display human-readable carrier names in the
checkout interface instead of internal identifiers.


Open src/lib/data/fulfillment.ts
[https://github.com/gorgojs/medusa-plugins/blob/7aa21a2d0331f60495ad85be74fcaa1aa86dd2a5/examples/fulfillment-apiship/medusa-storefront/src/lib/data/fulfillment.ts#L70-L134]
and add the following helpers:


Directory structure in the Medusa Storefront after updating the file for
fulfillment
[https://github.com/user-attachments/assets/c37d99e7-403a-4fef-84dc-ed351087a4dc]


// ... other helpers

export const retrieveCalculation = async (
  cartId: string,
  shippingOptionId: string
) => {
  const headers = {
    ...(await getAuthHeaders()),

  }

  const next = {
    ...(await getCacheOptions("fulfillment")),
  }

  const body = { cart_id: cartId }

  return sdk.client
    .fetch<Record<string, unknown>>(
      `/store/apiship/${shippingOptionId}/calculate`,
      {
        method: "POST",
        headers,
        body,
        next,
      }
    )
    .then(({ data }) => data)
    .catch((e) => {
      return null
    })
}

export const getPointAddresses = async (
  cartId: string,
  shippingOptionId: string,
  pointIds: Array<number>
) => {
  const headers = {
    ...(await getAuthHeaders()),
  }

  const next = {
    ...(await getCacheOptions("fulfillment")),
  }

  const body = {
    cartId,
    shippingOptionId,
    pointIds
  }

  return sdk.client
    .fetch<{
      points: any[]
      meta: any
    }>(`/store/apiship/points`, {
      method: "POST",
      headers,
      body,
      next,
    })
    .catch((e) => {
      console.error("getPointsAddresses error", e)
      return null
    })
}

export const retrieveProviders = async () => {
  const headers = {
    ...(await getAuthHeaders()),
  }

  const next = {
    ...(await getCacheOptions("fulfillment")),
  }

  return sdk.client
    .fetch<{
      providers: Array<{
        key: string
        name: string
        description: string | null
      }>
    }>(`/store/apiship/providers`, {
      method: "POST",
      headers,
      next,
    })
    .catch((e) => {
      console.error("retrieveProviders error", e)
      return null
    })
}



The retrieveCalculation request returns available delivery tariffs together with
the pickup point identifiers they apply to. The getPointAddresses request
resolves those identifiers into full pickup point data, such as addresses and
coordinates, which can then be displayed in the checkout interface.


In addition, the storefront fetches the list of ApiShip providers to display
human-friendly carrier names in the UI.



4. TYPE DEFINITIONS


The storefront integration relies on a small set of shared types that describe
the data returned by the ApiShip calculation endpoint and the data persisted in
the cart as the user’s delivery selection. These types are used across the map
UI, courier and pickup points modal windows, and the chosen component to keep
the flow consistent and type-safe.


Open src/modules/checkout/components/shipping/apiship/types/index.ts
[https://github.com/gorgojs/medusa-plugins/blob/7aa21a2d0331f60495ad85be74fcaa1aa86dd2a5/examples/fulfillment-apiship/medusa-storefront/src/modules/checkout/components/shipping-address/index.tsx#L212]
and add the following types:


Directory structure in the Medusa Storefront after creating the file for ApiShip
types
[https://github.com/user-attachments/assets/759f8e54-1f6b-4371-a518-78bddcdcf0f1]


export type ApishipCalculation = {
  deliveryToDoor?: Array<{
    providerKey: string
    tariffs?: Array<
      Omit<ApishipTariff, "key" | "providerKey">
    >
  }>
  deliveryToPoint?: Array<{
    providerKey: string
    tariffs?: Array<
      Omit<ApishipTariff, "key" | "providerKey"> & { pointIds?: number[] }
    >
  }>
}

export type ApishipTariff = {
  key: string
  providerKey: string
  tariffProviderId?: string
  tariffId?: number
  tariffName?: string
  deliveryCost?: number
  deliveryCostOriginal?: number
  daysMin?: number
  daysMax?: number
  calendarDaysMin?: number
  calendarDaysMax?: number
  workDaysMin?: number
  workDaysMax?: number
}

export type ApishipPoint = {
  id: string
  providerKey?: string
  availableOperation?: number
  name?: string
  description?: string
  worktime?: Record<string, string>
  photos?: string[]
  timetable?: string
  lat: number
  lng: number
  code?: string
  postIndex?: string
  region?: string
  city?: string
  address?: string
  phone?: string
}

export type Chosen = {
  deliveryType: number
  tariff: ApishipTariff
  point?: ApishipPoint
}



ApishipCalculation represents the calculated delivery options returned by the
store API, separated into to door and to point groups by provider. Chosen is the
normalized payload that the storefront saves in the cart once the user picks a
tariff and a pickup point.



5. UTILITIES


The storefront integration uses a set of shared utilities to keep the UI
consistent and to avoid duplicating logic across the components. These helpers
handle delivery time formatting, stable callback references for async effects,
deterministic tariff keys for selection, scroll locking for modal windows, and
mapping pickup point tariffs into a structure that is easy to render.


Open src/modules/checkout/components/shipping/apiship/utils/index.ts
[https://github.com/gorgojs/medusa-plugins/blob/7aa21a2d0331f60495ad85be74fcaa1aa86dd2a5/examples/fulfillment-apiship/medusa-storefront/src/modules/checkout/components/shipping-address/index.tsx#L212]
and add the following helpers:


Directory structure in the Medusa Storefront after creating the file for ApiShip
utilities
[https://github.com/user-attachments/assets/a59ef69b-72e1-4dba-b094-793e39d978ef]


import {
  ApishipCalculation,
  ApishipTariff,
} from "../types"
import { useEffect, useRef } from "react"

export function days(tariff: ApishipTariff) {
  const min = tariff.daysMin ?? 0
  const max = tariff.daysMax ?? 0
  if (!min && !max) return null
  if (min === max) return min === 1 ? `${min} day` : `${min} days`
  return `${min}–${max} days`
}

export function useLatestRef<T>(value: T) {
  const ref = useRef(value)
  useEffect(() => {
    ref.current = value
  }, [value])
  return ref
}

export function buildTariffKey (
  providerKey: string,
  tariff: Omit<ApishipTariff, "key" | "providerKey">,
  idx: number
) {
  return `${providerKey}:${tariff.tariffId ?? tariff.tariffProviderId ?? tariff.tariffName ?? idx}`
}

export function useLockBodyScroll(locked: boolean) {
  useEffect(() => {
    if (!locked) return

    const body = document.body
    const html = document.documentElement

    const prevBodyOverflow = body.style.overflow
    const prevBodyPaddingRight = body.style.paddingRight
    const prevHtmlOverflow = html.style.overflow

    const scrollbarWidth = window.innerWidth - html.clientWidth
    if (scrollbarWidth > 0) {
      body.style.paddingRight = `${scrollbarWidth}px`
    }

    body.style.overflow = "hidden"
    html.style.overflow = "hidden"

    return () => {
      body.style.overflow = prevBodyOverflow
      body.style.paddingRight = prevBodyPaddingRight
      html.style.overflow = prevHtmlOverflow
    }
  }, [locked])
}

export function useAsyncEffect(fn: (isCancelled: () => boolean) => Promise<void>, deps: any[]) {
  useEffect(() => {
    let cancelled = false
    const isCancelled = () => cancelled
    fn(isCancelled).catch((e) => console.error(e))
    return () => { cancelled = true }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, deps)
}

export function buildTariffsByPointId(calculation?: ApishipCalculation | null) {
  const map: Record<string, ApishipTariff[]> = {}
  calculation?.deliveryToPoint?.forEach(({ providerKey, tariffs }) => {
    tariffs?.forEach((tariff) => {
      for (const pointId of tariff.pointIds ?? []) {
        const key = `${providerKey}:${tariff.tariffProviderId ?? ""}:${tariff.tariffId ?? ""}`
        const entry: ApishipTariff = { key, providerKey, ...tariff }
        const arr = (map[String(pointId)] ??= [])
        if (!arr.some((t) => t.key === key)) arr.push(entry)
      }
    })
  })
  return map
}

export function extractPointIds(map: Record<string, ApishipTariff[]>) {
  return Object.keys(map).map(Number).filter(Number.isFinite)
}



These utilities are referenced by the modal windows and the map for formatting
delivery times, keeping selection keys stable between renders, safely running
async effects without state updates after unmount, and correctly preparing the
pickup point data model used to render tariffs per point.



6. PICKUP POINT MAP


This component is responsible for rendering the Yandex Map, placing pickup point
markers on it, and showing a details panel with available tariffs when a point
is selected.


Open src/modules/checkout/components/shipping/apiship/apiship-map.tsx
[https://github.com/gorgojs/medusa-plugins/blob/7aa21a2d0331f60495ad85be74fcaa1aa86dd2a5/examples/fulfillment-apiship/medusa-storefront/src/modules/checkout/components/shipping-address/index.tsx#L212]
and add the following:


Directory structure in the Medusa Storefront after creating the file for pickup
point map
[https://github.com/user-attachments/assets/bffa1d01-eaf7-4c54-93bb-927b34a139a7]


"use client"

import { useCallback, useEffect, useMemo, useRef } from "react"
import { Button, Heading, Text, clx, IconButton } from "@medusajs/ui"
import { Loader, XMark } from "@medusajs/icons"
import { Radio, RadioGroup } from "@headlessui/react"
import MedusaRadio from "@modules/common/components/radio"
import {
  ApishipPoint,
  ApishipTariff
} from "./types"
import {
  days,
  useLatestRef
} from "./utils"

const DEFAULT_CENTER: [number, number] = [37.618423, 55.751244]

type ApishipMapProps = {
  points: ApishipPoint[]
  tariffsByPointId: Record<string, ApishipTariff[]>
  isLoading?: boolean
  selectedPointId: string | null
  selectedTariffKey: string | null
  isPanelOpen: boolean
  onClosePanel: () => void
  onSelectPoint: (id: string) => void
  onSelectTariff: (tariffKey: string) => void
  onChoose: (payload: { point: ApishipPoint; tariff: ApishipTariff }) => void
  chosen?: { pointId?: string; tariffKey?: string } | null
  providersMap: Record<string, string>
}

const WEEK_DAYS = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"] as const

const Schedule = ({ worktime }: { worktime: Record<string, string> }) => {
  if (!worktime || Object.keys(worktime).length === 0) return null
  return (
    <div className="flex flex-col gap-[1px]">
      {Object.keys(worktime).map((day) => {
        const label = WEEK_DAYS[Number(day) - 1]
        const time = worktime[day]
        return (
          <div className="flex flex-row justify-between" key={day}>
            <Text className="txt-medium text-ui-fg-subtle">
              {label}
            </Text>
            <Text className="text-ui-fg-muted">
              {time}
            </Text>
          </div>
        )
      })}
    </div>
  )
}

declare global {
  interface Window {
    ymaps3?: any
    __ymaps3_loading_promise__?: Promise<void>
  }
}

function ensureYmaps3Loaded(params: { apikey: string; lang?: string }): Promise<void> {
  if (typeof window === "undefined") return Promise.resolve()
  if (window.__ymaps3_loading_promise__) return window.__ymaps3_loading_promise__

  window.__ymaps3_loading_promise__ = new Promise<void>((resolve, reject) => {
    const existing = document.querySelector<HTMLScriptElement>('script[src^="https://api-maps.yandex.ru/v3/"]')
    if (existing) return resolve()

    const script = document.createElement("script")
    script.src = `https://api-maps.yandex.ru/v3/?apikey=${encodeURIComponent(params.apikey)}&lang=${encodeURIComponent(
      params.lang ?? "ru_RU"
    )}`
    script.async = true
    script.onload = () => resolve()
    script.onerror = () => reject(new Error(`Failed to load Yandex Maps JS API v3 script: ${script.src}`))
    document.head.appendChild(script)
  })

  return window.__ymaps3_loading_promise__
}

export const ApishipMap: React.FC<ApishipMapProps> = ({
  points,
  tariffsByPointId,
  isLoading,
  selectedPointId,
  selectedTariffKey,
  isPanelOpen,
  onClosePanel,
  onSelectPoint,
  onSelectTariff,
  onChoose,
  chosen,
  providersMap
}) => {
  const containerRef = useRef<HTMLDivElement | null>(null)
  const mapRef = useRef<any>(null)
  const markersRef = useRef<Map<string, { marker: any; el: HTMLDivElement }>>(new Map())
  const initPromiseRef = useRef<Promise<void> | null>(null)

  const isSameAsChosen =
    !!chosen?.pointId &&
    !!chosen?.tariffKey &&
    chosen.pointId === selectedPointId &&
    chosen.tariffKey === selectedTariffKey

  const onSelectPointRef = useLatestRef(onSelectPoint)

  const center = useMemo<[number, number]>(() => {
    const p = points?.[0]
    return p ? [p.lng, p.lat] : DEFAULT_CENTER
  }, [points])

  const activePoint = useMemo(() => {
    return selectedPointId ? points.find((p) => p.id === selectedPointId) ?? null : null
  }, [points, selectedPointId])

  const activeTariffs = useMemo(() => {
    if (!selectedPointId) return []
    return tariffsByPointId[selectedPointId] ?? []
  }, [tariffsByPointId, selectedPointId])

  const selectedTariff = useMemo(() => {
    if (!selectedTariffKey) return null
    return activeTariffs.find((t) => t.key === selectedTariffKey) ?? null
  }, [activeTariffs, selectedTariffKey])

  const clearMarkers = useCallback(() => {
    const map = mapRef.current
    if (!map) return
    for (const { marker } of markersRef.current.values()) {
      try {
        map.removeChild(marker)
      } catch { }
    }
    markersRef.current.clear()
  }, [])

  const destroyMap = useCallback(() => {
    clearMarkers()
    try {
      mapRef.current?.destroy?.()
    } catch { }
    mapRef.current = null
    initPromiseRef.current = null
  }, [clearMarkers])

  const applySelectionStyles = useCallback(() => {
    for (const [id, { el }] of markersRef.current.entries()) {
      const sel = id === selectedPointId

      el.style.background = sel ? "#3b82f6" : "white"
      el.style.border = sel ? "2px solid #1d4ed8" : "2px solid rgba(0,0,0,0.25)"

      const dot = el.firstElementChild as HTMLElement | null
      if (dot) {
        dot.style.border = sel
          ? "2px solid rgba(255,255,255,0.95)"
          : "2px solid rgba(0,0,0,0.25)"
      }
    }
  }, [selectedPointId])

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return
    let cancelled = false

    initPromiseRef.current = (async () => {
      const apikey = process.env.NEXT_PUBLIC_YANDEX_MAPS_API_KEY
      if (!apikey) throw new Error("NEXT_PUBLIC_YANDEX_MAPS_API_KEY is not set")

      await ensureYmaps3Loaded({ apikey, lang: "ru_RU" })
      if (cancelled) return

      const ymaps3 = window.ymaps3
      if (!ymaps3) return
      await ymaps3.ready
      if (cancelled) return

      ymaps3.import.registerCdn("https://cdn.jsdelivr.net/npm/{package}", "@yandex/ymaps3-default-ui-theme@0.0")

      const { YMap, YMapDefaultSchemeLayer, YMapDefaultFeaturesLayer } = ymaps3

      const map = new YMap(containerRef.current!, { location: { center, zoom: 10 } })
      map.addChild(new YMapDefaultSchemeLayer({}))
      map.addChild(new YMapDefaultFeaturesLayer({ zIndex: 1800 }))

      mapRef.current = map
    })().catch((e) => console.error("Yandex map init failed", e))

    return () => {
      cancelled = true
      destroyMap()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [destroyMap])

  useEffect(() => {
    (async () => {
      if (!initPromiseRef.current) return
      await initPromiseRef.current
      try {
        mapRef.current?.setLocation?.({ center, zoom: 10 })
      } catch { }
    })()
  }, [center])

  useEffect(() => {
    let cancelled = false;
    (async () => {
      if (!initPromiseRef.current) return
      await initPromiseRef.current
      if (cancelled) return

      const map = mapRef.current
      const ymaps3 = window.ymaps3
      if (!map || !ymaps3) return

      const { YMapMarker } = ymaps3

      clearMarkers()

      for (const p of points) {
        const el = document.createElement("div")

        const SIZE = 18

        el.style.width = `${SIZE}px`
        el.style.height = `${SIZE}px`

        el.style.background = "white"
        el.style.border = "2px solid rgba(0,0,0,0.25)"
        el.style.borderRadius = "50% 50% 50% 0"
        el.style.transform = "rotate(-45deg)"
        el.style.boxShadow = "0 2px 2px rgba(0,0,0,0.18)"
        el.style.cursor = "pointer"
        el.style.position = "relative"
        el.style.transformOrigin = "50% 50%"

        const dot = document.createElement("div")
        dot.style.width = "8px"
        dot.style.height = "8px"
        dot.style.background = "white"
        dot.style.border = "2px solid rgba(0,0,0,0.25)"
        dot.style.borderRadius = "9999px"
        dot.style.position = "absolute"
        dot.style.left = "50%"
        dot.style.top = "50%"
        dot.style.transform = "translate(-50%, -50%) rotate(45deg)"
        dot.style.boxSizing = "border-box"

        el.appendChild(dot)

        el.title = p.name ?? p.address ?? `Point ${p.id}`

        el.addEventListener("click", (e) => {
          e.preventDefault()
          e.stopPropagation()
          onSelectPointRef.current(p.id)
        })

        const marker = new YMapMarker({ coordinates: [p.lng, p.lat] }, el)
        map.addChild(marker)
        markersRef.current.set(p.id, { marker, el })
      }
      applySelectionStyles()
    })()

    return () => {
      cancelled = true
    }
  }, [points, clearMarkers, onSelectPointRef])

  useEffect(() => {
    applySelectionStyles()
  }, [applySelectionStyles])

  const showNoPoints = !isLoading && points.length === 0

  return (
    <div className="relative w-full h-full">
      <div ref={containerRef} className="w-full h-full" />
      {isLoading && (
        <div className="absolute inset-0 bg-white/80 flex items-center justify-center">
          <Loader />
        </div>
      )}
      {showNoPoints && (
        <div className="absolute inset-0 bg-white/80 flex items-center justify-center">
          <Text className="text-ui-fg-muted">No pickup points found for this shipping method.</Text>
        </div>
      )}
      {!isLoading && activePoint && isPanelOpen && !showNoPoints && (
        <div className="absolute left-0 top-0 z-[70] w-full md:w-[470px] h-full border-r bg-white flex flex-col min-h-0">
          <div className="flex flex-row justify-between p-[35px] pb-0 items-center">
            <Heading
              level="h2"
              className="flex flex-row text-3xl-regular gap-x-2 items-baseline"
            >
              {`${providersMap?.[activePoint.providerKey ?? ""] ?? ""} pickup point`.trimStart()}
            </Heading>
            <IconButton
              aria-label="Close"
              onClick={(e) => {
                e.preventDefault()
                e.stopPropagation()
                onClosePanel()
              }}
              className="shadow-none"
            >
              <XMark />
            </IconButton>
          </div>

          <div className="flex-1 min-h-0 overflow-y-auto p-[35px] pt-[18px] flex flex-col gap-[18px]">
            <div className="flex flex-col">
              <Text className="font-medium txt-medium text-ui-fg-base">
                {activePoint.name}
              </Text>
              <Text className="text-ui-fg-muted txt-medium">
                {activePoint.address}
              </Text>
            </div>

            <div className="flex flex-col gap-[10px]">
              <Text className="font-medium txt-medium text-ui-fg-base">Tariffs</Text>

