                            })
                          ) : calculatedPricesMap[option.id] ? (
                            option.provider_id === "apiship_apiship" ? (
                              "from " + convertToLocale({
                                amount: calculatedPricesMap[option.id],
                                currency_code: cart?.currency_code,
                              })
                            ) :
