// ... other payment button's components

type RobokassaPaymentProps = {
  cart: HttpTypes.StoreCart
  notReady: boolean
  "data-testid"?: string
}

const RobokassaPaymentButton: React.FC<RobokassaPaymentProps> = ({
  cart,
  notReady,
  "data-testid": dataTestId,
}) => {
  const [submitting, setSubmitting] = useState(false)
  const [errorMessage, setErrorMessage] = useState<string | null>(null)
  const router = useRouter()

  const paymentSession = cart.payment_collection?.payment_sessions?.find(
    session =>
      session.provider_id === "pp_robokassa_robokassa"
  )

  const handlePayment = () => {
    setSubmitting(true)
    const paymentUrl = (paymentSession?.data as any).paymentUrl
    if (paymentUrl) {
      router.push(paymentUrl)
    } else {
      setErrorMessage("Payment URL отсутствует")
      setSubmitting(false)
    }
  }

  return (
    <>
      <Button
        disabled={notReady}
        isLoading={submitting}
        onClick={handlePayment}
        data-testid={dataTestId}
        size="large"
      >
        Place order
      </Button>
      <ErrorMessage
        error={errorMessage}
        data-testid="robokassa-payment-error-message"
      />
    </>
  )
}



This component locates the Robokassa payment_session in the active cart and
reads data.paymentUrl. When the Place order button is clicked, the customer is
redirected to that URL to complete the payment on Robokassa's hosted checkout.


If paymentUrl is missing, the component displays an error message instead of
proceeding. The isLoading state provides visual feedback while the redirection
is being prepared.


The parent PaymentButton uses isRobokassa to determine whether to render the
RobokassaPaymentButton for the current session; otherwise, it shows a disabled
Select a payment method button.



5. PAYMENT CAPTURE API ROUTE


After the customer completes payment on the Robokassa page, he is redirected
back to the storefront. You need an API route to handle this callback, verify
the payment status, and complete the cart.


Create the src/app/api/capture-payment/[cartId]/route.ts
[https://github.com/gorgojs/medusa-plugins/blob/main/examples/payment-robokassa/medusa-storefront/src/app/api/capture-payment/%5BcartId%5D/route.ts]
