import { NextRequest, NextResponse } from "next/server"
import { revalidateTag } from "next/cache"
import {
  getCacheTag,
  getAuthHeaders,
  removeCartId
} from "@lib/data/cookies"
import { sdk } from "@lib/config"
import { placeOrder } from "@lib/data/cart"

type Params = Promise<{ cartId: string }>

export async function GET(req: NextRequest, { params }: { params: Params }) {
  const { cartId } = await params
  const { origin, searchParams } = req.nextUrl

  const countryCode = searchParams.get("country_code") || ""
  const headers = { ...(await getAuthHeaders()) }

  // Retreive fresh cart values
  const cartCacheTag = await getCacheTag("carts")
  revalidateTag(cartCacheTag)
  const { cart } = await sdk.store.cart.retrieve(cartId, {
    fields: "id, order_link.order_id"
  },
    headers
  )
  if (!cart) {
    return NextResponse.redirect(`${origin}/${countryCode}`)
  }

  const orderId = (cart as unknown as Record<string, any>).order_link?.order_id
  if (!orderId) {
    await placeOrder(cartId)
    // Fail when payment not authorized
    return NextResponse.redirect(
      `${origin}/${countryCode}/checkout?step=review&error=payment_failed`
    )
  }

  const orderCacheTag = await getCacheTag("orders")
  revalidateTag(orderCacheTag)
  removeCartId()
  return NextResponse.redirect(
    `${origin}/${countryCode}/order/${orderId}/confirmed`
  )
}



This API route handles the redirect from T-Kassa after a payment attempt. It
retrieves the latest state of the cart to ensure any updates made during payment
are reflected.


If the cart does not contain an associated order ID, the route tries to place an
order. If successful, the customer is redirected to the order confirmation page.
If any error happens during cart completion, the customer is redirected back to
the checkout page indicating an error, and he can proceed the checkout once
again.


When the payment is successful, the route revalidates the cached cart and order
data, removes the cart cookie, and redirects the customer to the order
confirmation page. This ensures a consistent post-payment experience while
keeping storefront data up to date.



FULL STOREFRONT INTEGRATION CODE EXAMPLE


