import { NextRequest, NextResponse } from "next/server"
import { revalidateTag } from "next/cache"
import {
  getCacheTag,
  getAuthHeaders,
  removeCartId
} from "@lib/data/cookies"
import { sdk } from "@lib/config"
import { placeOrder } from "@lib/data/cart"

type Params = Promise<{ cartId: string }>

export async function GET(req: NextRequest, { params }: { params: Params }) {
  const { cartId } = await params
  const { origin, searchParams } = req.nextUrl

  const countryCode = searchParams.get("country_code") || ""
  const headers = { ...(await getAuthHeaders()) }

  // Получить актуальные значения корзины
  const cartCacheTag = await getCacheTag("carts")
  revalidateTag(cartCacheTag)
  const { cart } = await sdk.store.cart.retrieve(cartId, {
    fields: "id, order_link.order_id"
  },
    headers
  )
  if (!cart) {
    return NextResponse.redirect(`${origin}/${countryCode}`)
  }

  const orderId = (cart as unknown as Record<string, any>).order_link?.order_id
  if (!orderId) {
    await placeOrder(cartId)
    // Ошибка при неавторизованном платеже
    return NextResponse.redirect(
      `${origin}/${countryCode}/checkout?step=review&error=payment_failed`
    )
  }

  const orderCacheTag = await getCacheTag("orders")
  revalidateTag(orderCacheTag)
  removeCartId()
  return NextResponse.redirect(
    `${origin}/${countryCode}/order/${orderId}/confirmed`
  )
}



Этот API-роут обрабатывает редирект от Robokassa после попытки оплаты. Он
получает актуальное состояние корзины, чтобы убедиться, что все изменения,
внесённые во время оплаты, были отражены.


Если в корзине нет связанного идентификатора заказа, обработчик роута пытается
оформить заказ. В случае успеха покупатель перенаправляется на страницу
подтверждения заказа. Если же при обработке корзины возникла ошибка, покупатель
возвращается на страницу оформления заказа с указанием ошибки и может повторить
процесс оплаты заказа.


Когда оплата проходит успешно, роут повторно валидирует кэшированные данные
корзины и заказа, удаляет cookie корзины и перенаправляет покупателя на страницу
подтверждения заказа. Это гарантирует корректное завершение платёжного процесса
и сохранение актуальных данных в витрине.



ПОЛНЫЙ ПРИМЕР КОДА ИНТЕГРАЦИИ В ВИТРИНУ


Вы можете ознакомиться с изменениями, внесенными в стартовый шаблон Medusa
Next.js Starter Template [https://github.com/medusajs/nextjs-starter-medusa], в
директории examples/medusa-storefront
[https://github.com/gorgojs/medusa-plugins/tree/main/examples/payment-robokassa/medusa-storefront].


Полный код интеграции можно посмотреть в разделе сomparison page
[https://github.com/gorgojs/medusa-plugins/compare/%40gorgo/medusa-payment-robokassa%400.0.1...main]
— откройте вкладку Files changed и изучите различия в каталоге
examples/payment-robokassa/medusa-storefront. Или запустите diff в терминале:


